VALUES ('natural-number-division-4-div-2-equals-2', 'domain-natural-number-arithmetic', 'Four Divided By Two Equals Two', 'foundation-internalized', 'NaturalDiv(4,2) = 2 in the Peano naturals (exact division; partial where the divisor does not divide the dividend).', 'Closed derivation using div-base and div-sub-step (repeated truncated subtraction); exact because the remainder reaches zero; no imported theorem.', 'FULLY_INTERNALIZED_FOR_SCOPE', 'PeanoNaturalNumberKernel: Zero, Successor, and the recursive operation definitions are the trusted base.', 0, 'div_4_2_equals_2', 'domains/natural-number-arithmetic/theorem-contract.json', '1.0.0', FALSE, 'Model the remainder and prove the division algorithm 4 = 2*q + r with 0<=r<2.') ON CONFLICT (theorem_id) DO UPDATE SET domain_id = EXCLUDED.domain_id, title = EXCLUDED.title, theorem_kind = EXCLUDED.theorem_kind, statement = EXCLUDED.statement, scope = EXCLUDED.scope, proof_status_id = EXCLUDED.proof_status_id, trust_boundary = EXCLUDED.trust_boundary, active_import_count = EXCLUDED.active_import_count, root_fact_id = EXCLUDED.root_fact_id, contract_path = EXCLUDED.contract_path, current_version = EXCLUDED.current_version, is_flagship = EXCLUDED.is_flagship, next_target = EXCLUDED.next_target;

