INSERT INTO loops (loop_id, loop_order, title, status, new_concept, domain_question, witness_summary, next_frontier, epistemic_tier, domain_id)
VALUES ('loop-572', 572, 'Natural-number addition: 2+2=4', 'complete', 'peano-addition-internalized', 'Can 2+2=4 be derived from Zero/Successor without importing its own conclusion?', 'Five-step reduction S(S(0))+S(S(0)) -> S(S(S(S(0)))) via add-succ-left x2 and add-zero-left; recognized as numeral 4.', 'Add truncated subtraction as the first partial operation.', 'foundation-internalization', 'domain-natural-number-arithmetic') ON CONFLICT (loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, epistemic_tier = EXCLUDED.epistemic_tier, domain_id = EXCLUDED.domain_id;

INSERT INTO loops (loop_id, loop_order, title, status, new_concept, domain_question, witness_summary, next_frontier, epistemic_tier, domain_id)
VALUES ('loop-573', 573, 'Natural-number subtraction: 4-2=2', 'complete', 'peano-truncated-subtraction-internalized', 'Does truncated subtraction stay total on the naturals while remaining definitionally exact for 4-2?', 'Four-step reduction cancelling successors pairwise then n-0=n; normal form S(S(0)) = numeral 2.', 'Add multiplication, reusing internalized addition.', 'foundation-internalization', 'domain-natural-number-arithmetic') ON CONFLICT (loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, epistemic_tier = EXCLUDED.epistemic_tier, domain_id = EXCLUDED.domain_id;

INSERT INTO loops (loop_id, loop_order, title, status, new_concept, domain_question, witness_summary, next_frontier, epistemic_tier, domain_id)
VALUES ('loop-574', 574, 'Natural-number multiplication: 2*2=4', 'complete', 'peano-multiplication-internalized', 'Can multiplication reduce through the already-internalized addition rather than re-importing it?', 'mul-succ-left x2 and mul-zero-left expand 2*2 to 2+(2+0), which reduces to 4 via internalized addition.', 'Add exact division as repeated truncated subtraction.', 'foundation-internalization', 'domain-natural-number-arithmetic') ON CONFLICT (loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, epistemic_tier = EXCLUDED.epistemic_tier, domain_id = EXCLUDED.domain_id;

INSERT INTO loops (loop_id, loop_order, title, status, new_concept, domain_question, witness_summary, next_frontier, epistemic_tier, domain_id)
VALUES ('loop-575', 575, 'Natural-number division: 4/2=2', 'complete', 'peano-exact-division-internalized', 'Can exact division be witnessed as repeated truncated subtraction that terminates when the remainder hits zero?', 'div-sub-step x2 reach a zero dividend (base case), quotient increments 1+1+0 = numeral 2; reuses internalized subtraction.', 'Model remainder r and the division algorithm 4 = 2q + r; then close the domain in the cleanup loop.', 'foundation-internalization', 'domain-natural-number-arithmetic') ON CONFLICT (loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, epistemic_tier = EXCLUDED.epistemic_tier, domain_id = EXCLUDED.domain_id;

